class Solution:
    def maxTotalFruits(self, fruits, startPos, k):
        n = len(fruits)
        positions = [f[0] for f in fruits]
        prefix = [0] * (n + 1)
        for i in range(n):
            prefix[i + 1] = prefix[i] + fruits[i][1]
        best = 0
        for l in range(n):
            if positions[l] > startPos + k:
                break
            for r in range(l, n):
                dl = max(startPos - positions[l], 0)
                dr = max(positions[r] - startPos, 0)
                cost = dl + dr + min(dl, dr)
                if cost > k:
                    break
                best = max(best, prefix[r + 1] - prefix[l])
        return best

