        positions = [f[0] for f in fruits]
        prefix = [0] * (n + 1)
        for i in range(n):
            prefix[i + 1] = prefix[i] + fruits[i][1]
        left = 0
        ans = 0
        for right in range(n):
            while left <= right:
                dl = max(startPos - positions[left], 0)
                dr = max(positions[right] - startPos, 0)
                cost = dl + dr + min(dl, dr)
                if cost <= k:
                    break
                left += 1
            ans = max(ans, prefix[right + 1] - prefix[left])
        return ans

