var maxTotalFruits = function(fruits, startPos, k) {
    const n = fruits.length;
    const positions = fruits.map(f => f[0]);
    const prefix = new Array(n + 1).fill(0);
    for (let i = 0; i < n; i++) prefix[i + 1] = prefix[i] + fruits[i][1];
    let left = 0, ans = 0;
    for (let right = 0; right < n; right++) {
        while (left <= right) {
            const dl = Math.max(startPos - positions[left], 0);
            const dr = Math.max(positions[right] - startPos, 0);
            const cost = dl + dr + Math.min(dl, dr);
            if (cost <= k) break;
            left++;
        }
        ans = Math.max(ans, prefix[right + 1] - prefix[left]);
    }
    return ans;
};
